import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o as t,c as p,a as n,b as o,e as c,f as l}from"./app-e3619739.js";const i={},u=l(`<h3 id="是什么" tabindex="-1"><a class="header-anchor" href="#是什么" aria-hidden="true">#</a> 是什么</h3><ol><li>是异步编程的一种解决方法，它是一个构造函数，由它的实例对象来封装一个异步操作，并且可以获取其成功或失败的结果。构造函数<code>Promise</code>内部自动执行一个执行器函数<code>executor</code>，执行器函数接收两个参数<code>resolve、reject</code>两个回调函数，<code>executor</code>执行器函数是同步回调函数。</li><li>有三个状态：<code>pending、fulfilled、rejected</code>。实例的状态只能由<code>pending</code>转为<code>fulfilled或rejected</code>状态，并且状态一经改变，就没办法再被改变了。</li><li>状态如何改变的呢？通过<code>resolve()</code>将状态改为fulfilled；<code>reject()</code>函数将状态改为rejected；</li><li>回调地狱：回调函数嵌套使用，不利于阅读以及异常处理，Promise的链式调用解决了回调地狱。它实例对象具有<code>then和catch</code>方法，而它们的返回结果依然是一个Promise对象，因此可以使用<code>.符号</code>进行链式调用</li></ol><h3 id="promise构造函数-promise-excutor" tabindex="-1"><a class="header-anchor" href="#promise构造函数-promise-excutor" aria-hidden="true">#</a> Promise构造函数 Promise(excutor){}</h3><ol><li>excutor函数:同步执行<code>(resolve, reject)=&gt;{}</code>, excutor会在Promise内部立即同步回调</li><li>resolve函数:内部定义成功时我们调用的函数<code> value =&gt;{}</code></li><li>reject函数:内部定义失败时我们调用的函数 <code>reason=&gt;{}</code></li></ol><h3 id="promise原型上的方法" tabindex="-1"><a class="header-anchor" href="#promise原型上的方法" aria-hidden="true">#</a> Promise原型上的方法</h3><ol><li><code> Promise.prototype.then((onResolved, onRejected)=&gt; {})</code>：<br> a. <code>onResolved</code>函数:成功的回调函数(value)=&gt;{}<br> b. <code>onRejected</code>函数:失败的回调函数(reason)=&gt;{}<br> c. 成功或失败的回调函数都会返回一个新的Promise，也就是promise能链式书写的原因</li><li><code>Promise.prototype.catch((onRejected)=&gt; {})</code>:<br> onRejected函数:失败的回调函数(reason)=&gt;{}。是then()的语法糖，相当于:then(undefined，onRejected)</li><li><code>Promise.prototype.finally</code>：finally()方法用于指定不管 Promise 对象最后状态如何，都会执行的操作。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 Promise构造函数 Promise(excutor){}</span>
<span class="token keyword">const</span> p1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span> 
  <span class="token comment">// ...异步操作</span>
  <span class="token function">resolve</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// 2 Promise.resolve方法 Promise.reject方法</span>
<span class="token keyword">const</span> p2 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">resolve</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span> 
<span class="token keyword">const</span> p3 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">reject</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>  
<span class="token comment">// 3 原型上的方法 Promise.prototype.then((onResolved, onRejected)=&gt; {})  </span>
<span class="token comment">// 4 原型上的方法 Promise.prototype.catch((onRejected)=&gt; {})</span>
<span class="token comment">// onResolved函数:成功的回调函数(value)=&gt;{}; onRejected函数:失败的回调函数(reason)=&gt;{}</span>
p1<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">// 结果：1</span>
p2<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">// 结果：2</span>
p3<span class="token punctuation">.</span><span class="token function">catch</span><span class="token punctuation">(</span><span class="token parameter">reason</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;catch&#39;</span><span class="token punctuation">,</span> reason<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token comment">// 结果：catch 3</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="promise身上的方法" tabindex="-1"><a class="header-anchor" href="#promise身上的方法" aria-hidden="true">#</a> Promise身上的方法</h3><ol><li><code>Promise.resolve方法 (value)=&gt;{}</code>：返回一个成功/失败的promise对象，value参数是成功的数据或promise对象</li><li><code>Promise.reject方法 (reason)=&gt;{}</code>：返回一个失败的promise对象，reason:失败的原因</li><li><code>Promise.all方法 (promises)=&gt;{}</code>： 返回一个新的promise，参数是promise数组。只有所有的promise都成功才成功，一个失败了就直接失败了<code>（全部成功，任一失败立即拒绝</code>）</li><li><code>Promise.race方法 (promises)=&gt;{}</code>： 返回一个新的promise，第一个完成的Promise的状态就是最终的结果状态<code>（第一个响应的是啥就是啥）</code></li><li><code>Promise.allSettled方法 (promises)=&gt;{</code>}：返回一个新的promise，状态总是已完成,用来确定一组异步操作是否都结束了<code>(全部返回，不管成功或失败)</code></li><li><code>Promise.any方法 (promises)=&gt;{}</code>： 返回一个新的promise，状态总是已完成,只要参数实例有一个变成fulfilled状态，包装实例就会变成 fulfilled状态<code>（任一成功，全部失败才拒绝）</code>;如果所有参数实例都变成rejected状态，包装实例就会变成rejected状态。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 Promise构造函数 Promise(excutor){}</span>
<span class="token keyword">const</span> p1 <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span> 
  <span class="token comment">// ...异步操作</span>
  <span class="token function">resolve</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// 2 Promise身上的几个方法使用</span>
<span class="token keyword">const</span> p2 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">resolve</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span>  <span class="token comment">//Promise.resolve方法</span>
<span class="token keyword">const</span> p3 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">reject</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span>  <span class="token comment">//Promise.reject方法</span>
<span class="token keyword">const</span> p4 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">all</span><span class="token punctuation">(</span><span class="token punctuation">[</span>p1<span class="token punctuation">,</span> p2<span class="token punctuation">,</span> p3<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//Promise.all方法</span>
<span class="token keyword">const</span> p5 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">race</span><span class="token punctuation">(</span><span class="token punctuation">[</span>p1<span class="token punctuation">,</span> p2<span class="token punctuation">,</span> p3<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//Promise.race方法</span>
<span class="token keyword">const</span> p6 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">allSettled</span><span class="token punctuation">(</span><span class="token punctuation">[</span>p1<span class="token punctuation">,</span> p2<span class="token punctuation">,</span> p3<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//Promise.allSettled方法</span>
<span class="token keyword">const</span> p7 <span class="token operator">=</span> Promise<span class="token punctuation">.</span><span class="token function">any</span><span class="token punctuation">(</span><span class="token punctuation">[</span>p1<span class="token punctuation">,</span> p2<span class="token punctuation">,</span> p3<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token comment">//Promise.any方法</span>
<span class="token comment">// 对应all race allSettled any的结果</span>
p4<span class="token punctuation">.</span><span class="token function">catch</span><span class="token punctuation">(</span><span class="token parameter">reason</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;catch&#39;</span><span class="token punctuation">,</span> reason<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">// all结果：catch 3，全部成功，任一失败立即拒绝</span>
p5<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">// race结果：1，第一个响应的是啥就是啥</span>
p6<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token comment">// allSettled结果：[{&quot;status&quot;: &quot;fulfilled&quot;,&quot;value&quot;: 1},{&quot;status&quot;: &quot;fulfilled&quot;,&quot;value&quot;: 2}</span>
<span class="token comment">//,{&quot;status&quot;: &quot;rejected&quot;,&quot;reason&quot;: 3}]，全部返回，不管成功或失败</span>
p7<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token comment">// any结果：1 //任一成功，全部失败才拒绝</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="promise-all与promise-race的区别" tabindex="-1"><a class="header-anchor" href="#promise-all与promise-race的区别" aria-hidden="true">#</a> promise.all与promise.race的区别</h3><ol><li>相同点用来完成并行任务， 它接收一个数组，数组的每一项都是一个promise对象</li><li>不同点：<code>Promise.all 关注全部完成，Promise.race 关注最先响应</code></li><li><code>Promise.all</code>：只有所有的promise都成功才成功，一个失败了就直接失败了。<br> a.当数组中所有的promise的状态都达到resolved的时候，all方法的状态就会变成resolved;<br> b.有一个状态变成了rejected，那么all方法的状态就会变成rejected。</li><li><code>Promise.race</code>: 第一个完成的Promise的状态就是最终的结果状态。<br> a.如果第一个promise对象状态变成resolved状态就是resolved；第一个promise变成rejected，状态就是rejected。</li></ol><h3 id="promise几个关键问题" tabindex="-1"><a class="header-anchor" href="#promise几个关键问题" aria-hidden="true">#</a> Promise几个关键问题</h3><ol><li><code>new Promise(executor)</code> 中的执行器以及<code> .then、.catch</code> 都是同步的，但是执行器中的异步操作是异步的，.then 和 .catch 中的回调函数也是异步的。</li><li><code>promise.then与promise.catch</code>的区别：catch()是then()的语法糖，相当于:then(undefined，onRejected)</li><li>promise怎么串联多个操作任务？通过then的链式调用串连多个同步/异步任务，因为promise的 then() 返回一个新的 promise</li><li><code>promise.then()</code>返回的新的promise状态是谁改变？由then里面回调执行的结果决定。</li></ol><blockquote><p>① 如果<code>抛出异常</code>，新promise变为rejected;<br> ② 如果返回的是<code>非promise</code>，那么状态为已完成，value为返回值;<br> ③ 如果返回的是<code>promise</code>，那么状态由promise的状态决定</p></blockquote><ol start="5"><li>异常穿透：在Promise的链式调用链中，所有的then都没有指定错误的回调，则前面出现的异常会在最后失败的回调中处理。</li><li>值传透：链式调用的参数不是函数时，会发生值穿透，就传入的非函数值忽略，传入的是之前的函数参数。</li><li>如何中断promise链？在回调函数中返回一个pendding状态的promise对象：<code>return new Promise(()=&gt;{})</code></li></ol><h3 id="promise问题" tabindex="-1"><a class="header-anchor" href="#promise问题" aria-hidden="true">#</a> Promise问题</h3><ol><li>无法取消Promise，若没有状态变更，也无法停止 promise 的等待</li><li>不设定 then 或 catch 方法，构造函数(excutor函数)错误，无法捕获</li><li>未完成状态时，无法得知是刚开始，还是即将完成</li></ol><h3 id="手写一个简易promise" tabindex="-1"><a class="header-anchor" href="#手写一个简易promise" aria-hidden="true">#</a> 手写一个简易promise</h3><ol><li>定义Promise构造函数：① 定义<code>excutor</code>执行器函数是同步执行；② 声明<code>pending、fulfilled、rejected</code>三个全局状态；③ 定义<code>resolve()</code>修改状态以及异步执行所有成功的回调函数；④ 定义<code>reject()</code>修改状态以及异步执行所有失败的回调函数</li><li>定义Promise原型对象<code>then()</code>，参数是<code>onResolved, onRejected</code>两个回调；① 返回一个新的Promise对象，返回promise的结果由onResolved/onRejected执行结果决定。② 根据全局状态，如果是<code>fulfilled、rejected</code>则异步执行<code>onResolved/onRejected</code>，改变return的promise的状态；③ 如果是<code>pending</code>则push进数组等待被执行。</li><li>Promise原型对象<code>catch()</code>，返回一个新的Promise对象</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 Promise 构造函数 excutor执行器函数 同步执行</span>
<span class="token keyword">const</span> <span class="token constant">PENDING</span> <span class="token operator">=</span> <span class="token string">&#39;pending&#39;</span>
<span class="token keyword">const</span> <span class="token constant">RESOLVED</span> <span class="token operator">=</span> <span class="token string">&#39;fulfilled&#39;</span>
<span class="token keyword">const</span> <span class="token constant">REJECTED</span> <span class="token operator">=</span> <span class="token string">&#39;rejected&#39;</span>
<span class="token keyword">function</span> <span class="token function">Promise</span><span class="token punctuation">(</span><span class="token parameter">excutor</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
   <span class="token keyword">try</span><span class="token punctuation">{</span><span class="token comment">// excutor同步执行</span>
      <span class="token function">excutor</span><span class="token punctuation">(</span>resolve<span class="token punctuation">,</span> reject<span class="token punctuation">)</span> 
  <span class="token punctuation">}</span><span class="token keyword">catch</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">// 若执行器异常，promise 对象变为 rejected 状态</span>
      <span class="token function">reject</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>data <span class="token operator">=</span> <span class="token keyword">null</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>status <span class="token operator">=</span> <span class="token constant">PENDING</span> <span class="token comment">//状态默认是pending</span>
  <span class="token keyword">this</span><span class="token punctuation">.</span>callbacks <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span> <span class="token comment">//保存的回调数组，结构是[{onResolved(){},onRejected(){}}]</span>
  <span class="token comment">// 修改状态以及异步执行所有成功的回调函数</span>
  <span class="token keyword">function</span> <span class="token function">resolve</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
      <span class="token comment">// 状态只能修改一次</span>
      <span class="token keyword">if</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>status <span class="token operator">!==</span> <span class="token constant">PENDING</span><span class="token punctuation">)</span> <span class="token keyword">return</span>
      <span class="token comment">// 修改值与状态</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>status <span class="token operator">=</span> <span class="token constant">RESOLVED</span><span class="token punctuation">;</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span>data <span class="token operator">=</span> value<span class="token punctuation">;</span>
      <span class="token comment">// 回调数组有值则立马取出执行</span>
      <span class="token keyword">if</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">.</span>callbacks<span class="token punctuation">.</span>length <span class="token operator">&gt;</span> <span class="token number">0</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
          <span class="token comment">// 模拟异步执行所有成功的回调函数</span>
          <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
              <span class="token keyword">this</span><span class="token punctuation">.</span>callbacks<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token parameter">callbacksObj</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
                  callbacksObj<span class="token punctuation">.</span><span class="token function">onResolved</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
              <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
          <span class="token punctuation">}</span><span class="token punctuation">)</span>
      <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// reject同理 修改状态以及异步执行所有失败的回调函数</span>
<span class="token punctuation">}</span>
<span class="token comment">// 2 Promise原型对象then方法 返回一个新的Promise对象</span>
<span class="token class-name">Promise</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">then</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">onResolved<span class="token punctuation">,</span> onRejected</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token comment">// 返回一个新的Promise对象 返回promise的结果由onResolved/onRejected执行结果决定</span>
   <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
     <span class="token keyword">function</span> <span class="token function">handle</span><span class="token punctuation">(</span><span class="token parameter">callback</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
      <span class="token comment">// a. 如果抛出异常，新 promise 变为 rejected, reason为抛出的异常</span>
      <span class="token comment">// b. 如果返回的是非 promise 的任意值，新promise变为 resolved，value 为返回的值</span>
      <span class="token comment">// c. 如果返回的是另一个新 promise，此 promise 的结果就会成为新 promise 的结果</span>
        <span class="token keyword">try</span><span class="token punctuation">{</span>
            <span class="token keyword">let</span> result <span class="token operator">=</span> <span class="token function">callback</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>data<span class="token punctuation">)</span>
            <span class="token comment">//3 返回的是另一个新 promise，此 promise 的结果就会成为新 promise 的结果</span>
            <span class="token keyword">if</span><span class="token punctuation">(</span>result <span class="token keyword">instanceof</span> <span class="token class-name">Promise</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
                result<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span>
                    <span class="token parameter">value</span> <span class="token operator">=&gt;</span> <span class="token function">resolve</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 当result成功，返回的promise也成功</span>
                    <span class="token parameter">reason</span> <span class="token operator">=&gt;</span> <span class="token function">reject</span><span class="token punctuation">(</span>reason<span class="token punctuation">)</span> <span class="token comment">// 当result失败，返回的promise也失败</span>
                <span class="token punctuation">)</span>
            <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
                <span class="token function">resolve</span><span class="token punctuation">(</span>result<span class="token punctuation">)</span><span class="token comment">//2 如果返回的是非 promise 的任意值,promise变为 resolved</span>
            <span class="token punctuation">}</span>
        <span class="token punctuation">}</span><span class="token keyword">catch</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token function">reject</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token comment">//1 如果抛出异常 promise 变为 rejected</span>
    <span class="token punctuation">}</span>
     <span class="token comment">// resolved/rejected状态，则异步执行onResolved/onRejected，改变return的promise的状态</span>
     <span class="token keyword">if</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>status <span class="token operator">===</span> <span class="token constant">RESOLVED</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
          <span class="token function">handle</span><span class="token punctuation">(</span>onResolved<span class="token punctuation">)</span>
        <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token number">0</span><span class="token punctuation">)</span>
     <span class="token punctuation">}</span><span class="token keyword">else</span> <span class="token keyword">if</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>status <span class="token operator">===</span> <span class="token constant">REJECTED</span><span class="token punctuation">)</span><span class="token punctuation">{</span> 
       <span class="token function">setTimeout</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
          <span class="token function">handle</span><span class="token punctuation">(</span>onRejected<span class="token punctuation">)</span>
        <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token number">0</span>
     <span class="token punctuation">}</span><span class="token keyword">else</span> <span class="token keyword">if</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>status <span class="token operator">===</span> <span class="token constant">PENDING</span><span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">//push进数组等待被执行</span>
       self<span class="token punctuation">.</span>callbacks<span class="token punctuation">.</span><span class="token function">push</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
         <span class="token function">onResolved</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token function">handle</span><span class="token punctuation">(</span>onResolved<span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">,</span> 
         <span class="token function">onRejected</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span> <span class="token function">handle</span><span class="token punctuation">(</span>onRejected<span class="token punctuation">)</span> <span class="token punctuation">}</span>
       <span class="token punctuation">}</span><span class="token punctuation">)</span>
     <span class="token punctuation">}</span>    
   <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token comment">// Promise原型对象 catch 方法 返回一个新的Promise对象</span>
<span class="token class-name">Promise</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">catch</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">onRejected</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token keyword">undefined</span><span class="token punctuation">,</span> onRejected<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
<span class="token comment">// Promise函数对象resolve方法，返回一个新的Promise对象</span>
<span class="token comment">// 返回新promise得结果由value决定，如果value是一个非promise，那么返回成功的promise，value就是这个传入的参数;value是一个promise，那么返回的promise，执行结果取决于传入的promise；</span>
Promise<span class="token punctuation">.</span><span class="token function-variable function">resolve</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>value <span class="token keyword">instanceof</span> <span class="token class-name">Promise</span><span class="token punctuation">)</span> value<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span>resolve<span class="token punctuation">,</span>reject<span class="token punctuation">)</span>
    <span class="token keyword">else</span> <span class="token function">resolve</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token comment">// Promise函数对象reject方法，返回reason</span>
Promise<span class="token punctuation">.</span><span class="token function-variable function">reject</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span><span class="token punctuation">{</span> 
  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>  <span class="token function">reject</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span> <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h3><ol><li>手写Promise函数对象<code>all</code>方法，参数是promise类型的数组。返回一个新的Promise对象，所有promise成功则成功，只有一个失败就失败；</li><li>手写Promise函数对象<code>race</code>方法，参数是promise类型的数组。返回一个新的Promise对象，第一个响应的是啥就是啥。</li></ol><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1 all方法参数是promise类型的数组，返回一个新的Promise对象 所有promise成功则成功，只有一个失败就失败</span>
<span class="token comment">// 循环数组的每个promise实例的响应结果，有一个失败状态就直接reject(reason)；</span>
<span class="token comment">// 没有的话比较数组个数与成功状态的个数，相等了才resolve(values)</span>
Promise<span class="token punctuation">.</span><span class="token function-variable function">all</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">promises</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">let</span> values <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Array</span><span class="token punctuation">(</span>promises<span class="token punctuation">.</span>length<span class="token punctuation">)</span>
    <span class="token keyword">let</span> count <span class="token operator">=</span> <span class="token number">0</span>
    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
        promises<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">p<span class="token punctuation">,</span> index</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
            p<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
                count<span class="token operator">++</span>
                values<span class="token punctuation">[</span>index<span class="token punctuation">]</span> <span class="token operator">=</span> value<span class="token punctuation">;</span>
                <span class="token keyword">if</span><span class="token punctuation">(</span>promises<span class="token punctuation">.</span>length <span class="token operator">===</span> count<span class="token punctuation">)</span><span class="token punctuation">{</span><span class="token comment">// 全部成功，返回所有成功的值的数组</span>
                    <span class="token function">resolve</span><span class="token punctuation">(</span>values<span class="token punctuation">)</span>
                <span class="token punctuation">}</span>
            <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token parameter">reason</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span> <span class="token comment">// 出现失败就返回失败</span>
                <span class="token function">reject</span><span class="token punctuation">(</span>reason<span class="token punctuation">)</span>
            <span class="token punctuation">}</span><span class="token punctuation">)</span>
        <span class="token punctuation">}</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token comment">// 2 Promise函数对象race方法，参数是promise类型的数组</span>
<span class="token comment">// 返回一个新的Promise对象，第一个响应的是啥就是啥</span>
Promise<span class="token punctuation">.</span><span class="token function-variable function">race</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">resolve<span class="token punctuation">,</span> reject</span><span class="token punctuation">)</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
        promises<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">p<span class="token punctuation">,</span> index</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
            p<span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
                <span class="token function">resolve</span><span class="token punctuation">(</span>value<span class="token punctuation">)</span>
            <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token parameter">reason</span><span class="token operator">=&gt;</span><span class="token punctuation">{</span>
                <span class="token function">reject</span><span class="token punctuation">(</span>reason<span class="token punctuation">)</span>
            <span class="token punctuation">}</span><span class="token punctuation">)</span>
        <span class="token punctuation">}</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="链接" tabindex="-1"><a class="header-anchor" href="#链接" aria-hidden="true">#</a> 链接</h3>`,25),r={href:"https://www.bilibili.com/video/BV1MJ41197Eu/?spm_id_from=333.1387.search.video_card.click&vd_source=a3aec2a1dd5f478da3517872d0c61c5c",target:"_blank",rel:"noopener noreferrer"};function k(d,m){const s=e("ExternalLinkIcon");return t(),p("div",null,[u,n("p",null,[n("a",r,[o("尚硅谷Promise教程(promise前端进阶)"),c(s)])])])}const f=a(i,[["render",k],["__file","Promise由浅入深.html.vue"]]);export{f as default};
